import sys
from typing import List

class Solution:
    def minCoins(self, n: int, c: List[int]) -> int:
        c.sort(reverse=True)
        ans = 0
        for i in range(len(c)):
            if n >= c[i]:               n -= c[i]
                ans += 1
            else:
                break
        return ans

if __name__ == '__main__':
    try:
        n = int(input())
        c = list(map(int, input().split()))
        s = Solution()
        print(s.minCoins(n, c))
    except Exception as e:
        sys.exit("Error: " + str(e))

