#include <iostream>
#include <vector>
#include <algorithm>

using namespace std;

class Solution {
public:
    int minCoins(int n, vector<int>& c){
        sort(c.begin(), c.end(), greater<int>());
        int ans = 0;
        for(int i=0; i<c.size(); i++){
            if(n >= c[i]){
                n -= c[i];
                ans++;
            } else {
                break;
            }
        }
        return ans;
    }
};

int main(){
    int n;
    cin >> n;
    vector<int> c(n);
    for(int i=0; i<n; i++)
        cin >> c[i];
    Solution s;
    cout << s.minCoins(n, c) << endl;
    return 0;
}
